1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const BLOCK_SIZE = 3;
7	const BLOCK_PREMIUM = 60;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	type Step = { op: "quote"; items: Item[] };
20	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
21	type QuoteResult = { premium: number };
22	type ScenarioOutput = { results: QuoteResult[] };
23	
24	const groupCountsByType = (items: Item[]): Map<string, number> => {
25	  const counts = new Map<string, number>();
26	  for (const { type } of items) {
27	    counts.set(type, (counts.get(type) ?? 0) + 1);
28	  }
29	  return counts;
30	};
31	
32	const basePremiumForGroup = (type: string, count: number): number => {
33	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
34	  return count * BASE_PREMIUM[type];
35	};
36	
37	const basePremiumFor = (items: Item[]): number =>
38	  Array.from(groupCountsByType(items)).reduce(
39	    (total, [type, count]) => total + basePremiumForGroup(type, count),
40	    0,
41	  );
42	
43	const curseSurchargeFor = (item: Item): number =>
44	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;
45	
46	const highEnchantmentSurchargeFor = (item: Item): number =>
47	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
48	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
49	    : 0;
50	
51	const itemSurchargesFor = (items: Item[]): number =>
52	  items.reduce(
53	    (sum, item) =>
54	      sum + curseSurchargeFor(item) + highEnchantmentSurchargeFor(item),
55	    0,
56	  );
57	
58	const premiumFor = (items: Item[]): number => {
59	  const basePremium = basePremiumFor(items);
60	  const itemSurcharges = itemSurchargesFor(items);
61	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
62	  return Math.ceil(
63	    basePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE,
64	  );
65	};
66	
67	const quoteStep = ({ items }: Step): QuoteResult => ({
68	  premium: premiumFor(items),
69	});
70	
71	export const runScenario = (input: Scenario): ScenarioOutput => ({
72	  results: input.steps.map(quoteStep),
73	});
